import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { Card, Form, Button, ProgressBar, Badge, Alert } from 'react-bootstrap';
import { Upload, File, X, CheckCircle } from 'lucide-react';
import { toast } from 'react-toastify';
import { uploadDocument, getEmployees, getCategories } from '../api';
import './DocumentUpload.css';

const DocumentUpload = () => {
  const [formData, setFormData] = useState({
    employeeId: '',
    employeeName: '',
    store: '',
    documentType: '',
    issueDate: '',
    expiryDate: '',
    remarks: ''
  });
  const [files, setFiles] = useState([]);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const [employees, setEmployees] = useState([]);
  const [documentTypes, setDocumentTypes] = useState([]);
  const [uploadResults, setUploadResults] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [errors, setErrors] = useState({});
  const fileInputRef = useRef(null);
  const { user } = useAuth();

  useEffect(() => {
    loadEmployees();
    loadCategories();
  }, []);

  const loadEmployees = async () => {
    try {
      const response = await getEmployees();
      if (response.data && response.data.data) {
        setEmployees(response.data.data);
      }
    } catch (error) {
      console.error('Error loading employees:', error);
      toast.error('Error loading employees', {
        position: 'top-right',
        autoClose: 3000
      });
    }
  };

  const loadCategories = async () => {
    try {
      const response = await getCategories();
      if (response.data && response.data.data) {
        setDocumentTypes(response.data.data.map(cat => cat.name));
      }
    } catch (error) {
      console.error('Error loading categories:', error);
      setDocumentTypes([
        'ID Proof',
        'Driving License',
        'Medical Certificate',
        'Training Certificate',
        'Employment Contract',
        'Educational Certificate',
        'Address Proof',
        'Police Verification'
      ]);
    }
  };

  const stores = [
    'Store 1', 'Store 2', 'Store 3', 'Store 4', 'Store 5',
    'Store 6', 'Store 7', 'Store 8', 'Store 9', 'Store 10',
    'Store 11', 'Store 12', 'Store 13', 'Store 14', 'Store 15',
    'Store 16', 'Store 17', 'Store 18', 'Store 19', 'Store 20'
  ];

  const getTodayDate = () => {
    const today = new Date();
    return today.toISOString().split('T')[0];
  };

  const getMinExpiryDate = () => {
    if (!formData.issueDate) {
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      return tomorrow.toISOString().split('T')[0];
    }
    
    const issueDate = new Date(formData.issueDate);
    issueDate.setDate(issueDate.getDate() + 1);
    return issueDate.toISOString().split('T')[0];
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    
    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
    
    if (name === 'employeeId' && value) {
      const selectedEmployee = employees.find(emp => emp.id === value);
      if (selectedEmployee) {
        setFormData(prev => ({
          ...prev,
          employeeId: value,
          employeeName: selectedEmployee.name,
          store: selectedEmployee.store || prev.store
        }));
        return;
      }
    }
    
    if (name === 'issueDate') {
      setFormData(prev => {
        const newFormData = {
          ...prev,
          issueDate: value
        };
        
        if (prev.expiryDate && value) {
          const issueDate = new Date(value);
          const expiryDate = new Date(prev.expiryDate);
          if (expiryDate <= issueDate) {
            newFormData.expiryDate = '';
            toast.warning('Expiry date must be after issue date. Please select a new expiry date.', {
              position: 'top-right',
              autoClose: 3000
            });
          }
        }
        
        return newFormData;
      });
      return;
    }
    
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFileSelect(e.dataTransfer.files);
    }
  };

  const handleFileSelect = (selectedFiles) => {
    const fileArray = Array.from(selectedFiles);
    const validTypes = ['application/pdf', 'image/jpeg', 'image/png', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
    
    const validFiles = fileArray.filter(file => {
      if (validTypes.includes(file.type)) {
        return true;
      } else {
        toast.error(`Invalid file type: ${file.name}. Please upload PDF, DOCX, JPG, or PNG`, {
          position: 'top-right',
          autoClose: 3000
        });
        return false;
      }
    });
    
    setFiles(prev => [...prev, ...validFiles]);
    
    // Clear file error if files are selected
    if (validFiles.length > 0 && errors.files) {
      setErrors(prev => ({
        ...prev,
        files: ''
      }));
    }
  };

  const handleFileInput = (e) => {
    if (e.target.files && e.target.files.length > 0) {
      handleFileSelect(e.target.files);
      e.target.value = '';
    }
  };

  const removeFile = (index) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const validateForm = () => {
    const newErrors = {};
    
    if (!formData.employeeId) {
      newErrors.employeeId = 'Please select an employee';
    }
    
    if (!formData.employeeName) {
      newErrors.employeeName = 'Employee name is required';
    }
    
    if (!formData.store) {
      newErrors.store = 'Please select a store';
    }
    
    if (!formData.documentType) {
      newErrors.documentType = 'Please select a document type';
    }
    
    if (!formData.issueDate) {
      newErrors.issueDate = 'Issue date is required';
    }
    
    if (!formData.expiryDate) {
      newErrors.expiryDate = 'Expiry date is required';
    }
    
    if (formData.issueDate && formData.expiryDate) {
      const issueDate = new Date(formData.issueDate);
      const expiryDate = new Date(formData.expiryDate);
      
      if (expiryDate <= issueDate) {
        newErrors.expiryDate = 'Expiry date must be after issue date';
      }
    }
    
    if (files.length === 0) {
      newErrors.files = 'Please select at least one file to upload';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateForm()) {
      toast.error('Please fill all required fields correctly', {
        position: 'top-right',
        autoClose: 3000
      });
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);
    setShowResults(false);
    
    const results = [];
    const totalFiles = files.length;
    let successCount = 0;
    let failCount = 0;

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      
      try {
        const formDataToSend = new FormData();
        formDataToSend.append('file', file);
        formDataToSend.append('employeeId', formData.employeeId);
        formDataToSend.append('documentType', formData.documentType);
        formDataToSend.append('issueDate', formData.issueDate);
        formDataToSend.append('expiryDate', formData.expiryDate);
        if (formData.remarks) formDataToSend.append('remarks', formData.remarks);
        
        const uploader = (user?.name || user?.username) || 'System';
        formDataToSend.append('uploadedBy', uploader);
        formDataToSend.append('reason', formData.remarks || 'Initial upload');
        
        const response = await uploadDocument(formDataToSend);
        
        successCount++;
        results.push({
          fileName: file.name,
          status: 'success',
          message: 'Uploaded successfully',
          documentId: response.data?.data?.id
        });
        
      } catch (error) {
        failCount++;
        results.push({
          fileName: file.name,
          status: 'error',
          message: error.response?.data?.message || error.message || 'Upload failed'
        });
        console.error(`Error uploading ${file.name}:`, error);
      }
      
      setUploadProgress(Math.round(((i + 1) / totalFiles) * 100));
    }

    setIsUploading(false);
    setUploadResults(results);
    setShowResults(true);

    if (successCount === totalFiles) {
      toast.success(`Document uploaded successfully!`, {
        position: 'top-right',
        autoClose: 3000
      });
    } else if (successCount > 0) {
      toast.warning(`${successCount} of ${totalFiles} document(s) uploaded. ${failCount} failed.`, {
        position: 'top-right',
        autoClose: 4000
      });
    } else {
      toast.error(`All ${totalFiles} upload(s) failed`, {
        position: 'top-right',
        autoClose: 3000
      });
    }

    if (successCount === totalFiles) {
      setFormData({
        employeeId: '',
        employeeName: '',
        store: '',
        documentType: '',
        issueDate: '',
        expiryDate: '',
        remarks: ''
      });
      setFiles([]);
      setUploadProgress(0);
      setErrors({});
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
      
      setTimeout(() => {
        setShowResults(false);
        setUploadResults([]);
      }, 5000);
    }
  };

  return (
    <div className="document-upload">
      <Card className="upload-card">
        <Card.Header className="card-header-custom">
          <h3 className="mb-0">
            <Upload className="me-2" size={24} />
            Upload Employee Documents
          </h3>
        </Card.Header>
        <Card.Body>
          {showResults && uploadResults.length > 0 && (
            <Alert variant={uploadResults.every(r => r.status === 'success') ? 'success' : 'warning'} className="mb-4">
              <h5 className="mb-3">Upload Results:</h5>
              <div className="upload-results">
                {uploadResults.map((result, idx) => (
                  <div key={idx} className="d-flex align-items-center mb-2">
                    {result.status === 'success' ? (
                      <CheckCircle className="text-success me-2" size={18} />
                    ) : (
                      <X className="text-danger me-2" size={18} />
                    )}
                    <span className="me-2"><strong>{result.fileName}:</strong></span>
                    <span className={result.status === 'success' ? 'text-success' : 'text-danger'}>
                      {result.message}
                    </span>
                    {result.documentId && (
                      <Badge bg="info" className="ms-2">{result.documentId}</Badge>
                    )}
                  </div>
                ))}
              </div>
            </Alert>
          )}

          <Form onSubmit={handleSubmit}>
            <div className="row mb-4">
              <div className="col-md-6 mb-3">
                <Form.Label>Employee <span className="text-danger">*</span></Form.Label>
                <Form.Select
                  name="employeeId"
                  value={formData.employeeId}
                  onChange={handleInputChange}
                  required
                  isInvalid={!!errors.employeeId}
                >
                  <option value="">Select Employee</option>
                  {employees.map(emp => (
                    <option key={emp.id} value={emp.id}>
                      {emp.id} - {emp.name} ({emp.store})
                    </option>
                  ))}
                </Form.Select>
                {errors.employeeId ? (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.employeeId}
                  </Form.Control.Feedback>
                ) : (
                  <Form.Text className="text-muted">
                    Select an employee from the list
                  </Form.Text>
                )}
              </div>
              <div className="col-md-6 mb-3">
                <Form.Label>Employee Name <span className="text-danger">*</span></Form.Label>
                <Form.Control
                  type="text"
                  name="employeeName"
                  value={formData.employeeName}
                  onChange={handleInputChange}
                  placeholder="Auto-filled when employee is selected"
                  required
                  readOnly
                  style={{ backgroundColor: '#f8f9fa' }}
                  isInvalid={!!errors.employeeName}
                />
                {errors.employeeName && (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.employeeName}
                  </Form.Control.Feedback>
                )}
              </div>
              <div className="col-md-6 mb-3">
                <Form.Label>Store <span className="text-danger">*</span></Form.Label>
                <Form.Select
                  name="store"
                  value={formData.store}
                  onChange={handleInputChange}
                  required
                  isInvalid={!!errors.store}
                >
                  <option value="">Select Store</option>
                  {stores.map(store => (
                    <option key={store} value={store}>{store}</option>
                  ))}
                </Form.Select>
                {errors.store && (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.store}
                  </Form.Control.Feedback>
                )}
              </div>
              <div className="col-md-6 mb-3">
                <Form.Label>Document Type <span className="text-danger">*</span></Form.Label>
                <Form.Select
                  name="documentType"
                  value={formData.documentType}
                  onChange={handleInputChange}
                  required
                  isInvalid={!!errors.documentType}
                >
                  <option value="">Select Document Type</option>
                  {documentTypes.map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </Form.Select>
                {errors.documentType && (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.documentType}
                  </Form.Control.Feedback>
                )}
              </div>
              <div className="col-md-6 mb-3">
                <Form.Label>Issue Date <span className="text-danger">*</span></Form.Label>
                <Form.Control
                  type="date"
                  name="issueDate"
                  value={formData.issueDate}
                  onChange={handleInputChange}
                  min={getTodayDate()}
                  max={getTodayDate()}
                  required
                  isInvalid={!!errors.issueDate}
                />
                {errors.issueDate ? (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.issueDate}
                  </Form.Control.Feedback>
                ) : (
                  <Form.Text className="text-muted">
                    Can only select today's date
                  </Form.Text>
                )}
              </div>
              <div className="col-md-6 mb-3">
                <Form.Label>Expiry Date <span className="text-danger">*</span></Form.Label>
                <Form.Control
                  type="date"
                  name="expiryDate"
                  value={formData.expiryDate}
                  onChange={handleInputChange}
                  min={getMinExpiryDate()}
                  disabled={!formData.issueDate}
                  required
                  isInvalid={!!errors.expiryDate}
                />
                {errors.expiryDate ? (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.expiryDate}
                  </Form.Control.Feedback>
                ) : (
                  <Form.Text className="text-muted">
                    {formData.issueDate 
                      ? 'Must be after issue date' 
                      : 'Please select issue date first'}
                  </Form.Text>
                )}
              </div>
              <div className="col-md-12 mb-3">
                <Form.Label>Remarks</Form.Label>
                <Form.Control
                  as="textarea"
                  rows={3}
                  name="remarks"
                  value={formData.remarks}
                  onChange={handleInputChange}
                  placeholder="Enter any additional remarks or notes about these documents"
                />
              </div>
            </div>

            <div className="mb-4">
              <Form.Label>
                Upload Document(s) <span className="text-danger">*</span>
                {files.length > 0 && (
                  <Badge bg="primary" className="ms-2">{files.length} file(s) selected</Badge>
                )}
              </Form.Label>
              <div
                className={`drag-drop-area ${dragActive ? 'drag-active' : ''} ${files.length > 0 ? 'has-file' : ''} ${errors.files ? 'is-invalid' : ''}`}
                onDragEnter={handleDrag}
                onDragLeave={handleDrag}
                onDragOver={handleDrag}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
              >
                <input
                  ref={fileInputRef}
                  type="file"
                  onChange={handleFileInput}
                  accept=".pdf,.docx,.jpg,.jpeg,.png"
                  multiple
                  className="d-none"
                />
                {files.length > 0 ? (
                  <div className="files-list">
                    {files.map((file, index) => (
                      <div key={index} className="file-preview-item">
                        <File size={20} className="text-primary me-2" />
                        <span className="file-name">{file.name}</span>
                        <span className="file-size">({(file.size / 1024).toFixed(2)} KB)</span>
                        <Button
                          variant="link"
                          size="sm"
                          onClick={(e) => {
                            e.stopPropagation();
                            removeFile(index);
                          }}
                          className="remove-file-btn"
                        >
                          <X size={16} />
                        </Button>
                      </div>
                    ))}
                    <Button
                      variant="outline-primary"
                      size="sm"
                      onClick={(e) => {
                        e.stopPropagation();
                        fileInputRef.current?.click();
                      }}
                      className="mt-2"
                    >
                      <Upload size={16} className="me-1" />
                      Add More Files
                    </Button>
                  </div>
                ) : (
                  <div className="drag-drop-content">
                    <Upload size={48} className="text-muted mb-3" />
                    <p className="mb-1">Click to upload or drag and drop</p>
                    <p className="text-muted small">PDF, DOCX, JPG, PNG (Max 10MB per file) - Multiple files supported</p>
                  </div>
                )}
              </div>
              {errors.files && (
                <div className="text-danger small mt-1">{errors.files}</div>
              )}
            </div>

            {isUploading && (
              <div className="mb-4">
                <div className="d-flex justify-content-between mb-2">
                  <span>Uploading {files.length} file(s)...</span>
                  <span>{uploadProgress}%</span>
                </div>
                <ProgressBar now={uploadProgress} animated striped variant="primary" />
              </div>
            )}

            <Button
              type="submit"
              variant="primary"
              size="lg"
              className="w-100 upload-submit-btn"
              disabled={isUploading}
            >
              {isUploading ? `Uploading...` : `Upload Document${files.length !== 1 ? 's' : ''}`}
            </Button>
          </Form>
        </Card.Body>
      </Card>
    </div>
  );
};

export default DocumentUpload;
